function standing(
  rank: number,
  playerId: string,
  deckId: string | undefined,
  wins: number,
  losses: number,
  draws: number,
  points: number,
  omw: number,
  gw: number,
  ogw: number,
): FixtureStanding {
  return {
    rank,
    player: { id: playerId, name: '' },
    deck: deckId ? { id: deckId, name: '' } : undefined,
    record: draws > 0 ? `${wins}-${losses}-${draws}` : `${wins}-${losses}`,
    points,
    matchWins: wins,
    matchLosses: losses,
    matchDraws: draws,
    omw,
    gw,
    ogw,
  };
}

